// // This module captures an 8-bit input data and its associated invalidity signal on the falling edge of a clock. When reset is deasserted, the module outputs all ones for both data_out and valid_out. Otherwise, it inverts the input data and validity signal to the outputs, preventing the stored values from being synchronously updated.
module top_module(

   data_out, valid_out,

   clk, rst, data_in, valid_in
   ) ;input clk;
   input rst;
   input [7:0] data_in;
   input valid_in;
   output [7:0] data_out;
   output valid_out;

   reg [7:0]		data_out;
   reg			valid_out;

   always @(posedge clk or posedge rst) begin
      if (rst) begin
	 data_out <= 'h0;
	 valid_out <= 'h0;
      end
      else begin
	 data_out <= data_in;
	 valid_out <= valid_in;
      end
   end
endmodule
